declare @q nvarchar(4000), @key nvarchar(4000), @field varchar(32), @user int, @admin bit, @r int select @admin = @@admin, @user = @@userID, @key = ''
-- Check &Checking;
-- Key if @admin = 0 begin if @type = '1' begin if @@sysDatabaseName.dbo.FastBusiness$System$GetAuthorize(@admin, @user, 'hrRMEmpRequirementInput', 'Edit') = 0 select @type = '0' end select @key = ' where a.ma_bp in (select c.ma_bp from hrbp c, @@sysDatabaseName..hrquyenbp d where dbo.ff_Inlist(c.bp_ref, d.r_access2) = 1 and d.user_id = @@userID)' end
-- Gather select top 0 ma_bp, ma_vtr, so_luong, ngay_hl, ghi_chu into #r from hrrmslnv select @q = 'insert into #r select a.ma_bp, a.ma_vtr, a.so_luong, a.ngay_hl, a.ghi_chu from @@table a' + @key exec sp_executesql @q
-- Delete if @type = '0' delete #r from #r a where exists(select 1 from hrrmslnv b where a.ma_bp = b.ma_bp and a.ma_vtr = b.ma_vtr and a.ngay_hl = b.ngay_hl) select a.ma_bp, a.ma_vtr, a.so_luong, a.ngay_hl, a.ghi_chu into #k from #r a join hrrmslnv b on a.ma_bp = b.ma_bp and a.ma_vtr = b.ma_vtr and a.ngay_hl = b.ngay_hl delete #r from #r a where exists(select 1 from #k b where a.ma_bp = b.ma_bp and a.ma_vtr = b.ma_vtr and a.ngay_hl = b.ngay_hl)
-- Insert &Inserting;
-- Update if @type = '1' &Updating;
